  // src/libraries/loadFabric.js
  var FabricLoader = class {
    constructor() {
      this.isLoaded = false;
    }
    loadFabricJS(devMode) {
      return new Promise((resolve, reject) => {
        if (this.isLoaded || window.fabric) {
          console.log("Fabric.js is already loaded.");
          resolve();
          return;
        }
        const script = document.createElement("script");
        script.src = devMode ? "../../public/fabric.min.js" : "https://cdnjs.cloudflare.com/ajax/libs/fabric.js/5.3.0/fabric.min.js";
        script.onload = () => {
          this.isLoaded = true;
          console.log("Fabric.js loaded successfully!");
          resolve();
        };
        script.onerror = () => {
          console.error("Failed to load Fabric.js.");
          reject();
        };
        document.head.appendChild(script);
      });
    }
  };

  // src/core/WidgetButton.js
  function widgetButton({ text = "Capture Image", position = { bottom: "20px", right: "20px" }, onClick }) {
    const button = document.createElement("button");
    button.innerText = text;
    button.style.position = "fixed";
    button.style.bottom = position.bottom;
    button.style.right = position.right;
    button.style.padding = "10px 20px";
    button.style.background = "#007bff";
    button.style.color = "#fff";
    button.style.border = "none";
    button.style.borderRadius = "5px";
    button.style.cursor = "pointer";
    document.body.appendChild(button);
    if (onClick && typeof onClick === "function") {
      button.addEventListener("click", onClick);
    }
    console.log("Button created successfully!");
    return button;
  }

  // src/controls/CircleControl.js
  var CircleControl = class {
    constructor(canvas, enableCircleButton) {
      this.canvas = canvas;
      this.enableCircleButton = enableCircleButton;
      this.isDrawing = false;
      this.startPoint = null;
      this.tempEllipse = null;
      this.isActive = false;
    }
    // Activate the control
    activate() {
      this.isActive = true;
      this.enableCircleButton.classList.add("active");
      this.isDrawing = false;
      this.startPoint = null;
      this.tempEllipse = null;
      this.canvas.selection = false;
      this.canvas.defaultCursor = "crosshair";
    }
    // Deactivate the control
    deactivate() {
      this.isActive = false;
      this.enableCircleButton.classList.remove("active");
      this.isDrawing = false;
      this.startPoint = null;
      this.tempEllipse = null;
      this.canvas.selection = true;
      this.canvas.defaultCursor = "default";
    }
    // Handle mouse down event
    onMouseDown(event) {
      if (!this.isActive || event.target) return;
      this.isDrawing = true;
      this.startPoint = event.absolutePointer;
      this.tempEllipse = new fabric.Ellipse({
        left: this.startPoint.x,
        top: this.startPoint.y,
        rx: 1,
        // Initial small radius
        ry: 1,
        stroke: ColorSelect.getCurrentColor(),
        strokeWidth: 2,
        fill: "rgba(0,0,0,0)",
        // Transparent fill
        selectable: false,
        // Temporary non-selectable state
        hasControls: false,
        // Disable controls while drawing
        originX: "left",
        originY: "top",
        tempDrawingObject: true
        // Add this flag for temporary state
      });
      this.canvas.add(this.tempEllipse);
    }
    // Handle mouse move event
    onMouseMove(event) {
      if (!this.isActive || !this.isDrawing || !this.tempEllipse) return;
      const currentPoint = event.absolutePointer;
      const width = Math.abs(currentPoint.x - this.startPoint.x);
      const height = Math.abs(currentPoint.y - this.startPoint.y);
      this.tempEllipse.set({
        rx: width / 2,
        // Ellipse needs half width as radius
        ry: height / 2,
        // Ellipse needs half height as radius
        left: Math.min(this.startPoint.x, currentPoint.x),
        top: Math.min(this.startPoint.y, currentPoint.y)
      });
      this.canvas.requestRenderAll();
    }
    // Handle mouse up event
    onMouseUp() {
      if (!this.isActive || !this.isDrawing || !this.tempEllipse) return;
      this.isDrawing = false;
      const finalEllipse = new fabric.Ellipse({
        left: this.tempEllipse.left,
        top: this.tempEllipse.top,
        rx: this.tempEllipse.rx,
        ry: this.tempEllipse.ry,
        stroke: ColorSelect.getCurrentColor(),
        strokeWidth: 2,
        fill: "rgba(0,0,0,0)",
        selectable: true,
        hasControls: true,
        originX: "left",
        originY: "top",
        tempDrawingObject: false
        // This is the final object
      });
      this.canvas.remove(this.tempEllipse);
      this.canvas.add(finalEllipse);
      this.canvas.setActiveObject(finalEllipse);
      this.startPoint = null;
      this.tempEllipse = null;
      this.canvas.requestRenderAll();
    }
  };

  // src/controls/PaintToolControl.js
  var PaintToolControl = class {
    constructor(canvas, enablePaintButton) {
      this.canvas = canvas;
      this.enablePaintButton = enablePaintButton;
      this.isDrawing = false;
      this.isActive = false;
      this.currentPath = null;
    }
    // Activate the control
    activate() {
      this.isActive = true;
      this.enablePaintButton.classList.add("active");
      this.canvas.isDrawingMode = true;
      this.canvas.freeDrawingBrush = new fabric.PencilBrush(this.canvas);
      this.canvas.freeDrawingBrush.color = ColorSelect.getCurrentColor();
      this.canvas.freeDrawingBrush.width = 2;
    }
    // Deactivate the control
    deactivate() {
      this.isActive = false;
      this.enablePaintButton.classList.remove("active");
      this.canvas.isDrawingMode = false;
    }
  };

  // src/controls/MaskingControl.js
  var MaskingControl = class {
    constructor(canvas, enableMaskButton) {
      this.canvas = canvas;
      this.enableMaskButton = enableMaskButton;
      this.isDrawing = false;
      this.startPoint = null;
      this.tempMask = null;
      this.isActive = false;
    }
    // Activate the control
    activate() {
      this.isActive = true;
      this.enableMaskButton.classList.add("active");
      this.isDrawing = false;
      this.startPoint = null;
      this.tempMask = null;
      this.canvas.selection = false;
      this.canvas.defaultCursor = "crosshair";
    }
    // Deactivate the control
    deactivate() {
      this.isActive = false;
      this.enableMaskButton.classList.remove("active");
      this.isDrawing = false;
      this.startPoint = null;
      this.tempMask = null;
      this.canvas.selection = true;
      this.canvas.defaultCursor = "default";
    }
    // Handle mouse down event
    onMouseDown(event) {
      if (!this.isActive || event.target) return;
      this.isDrawing = true;
      this.startPoint = event.absolutePointer;
      this.tempMask = new fabric.Rect({
        left: this.startPoint.x,
        top: this.startPoint.y,
        width: 0,
        height: 0,
        fill: "rgba(255, 0, 0, 0.5)",
        // Semi-transparent red
        stroke: "red",
        strokeWidth: 2,
        selectable: false,
        // Temporary non-selectable state
        hasControls: false
        // Disable controls while drawing
      });
      this.canvas.add(this.tempMask);
    }
    // Handle mouse move event
    onMouseMove(event) {
      if (!this.isActive || !this.isDrawing || !this.tempMask) return;
      const currentPoint = event.absolutePointer;
      const width = currentPoint.x - this.startPoint.x;
      const height = currentPoint.y - this.startPoint.y;
      this.tempMask.set({
        width: Math.abs(width),
        height: Math.abs(height),
        left: width < 0 ? currentPoint.x : this.startPoint.x,
        top: height < 0 ? currentPoint.y : this.startPoint.y
      });
      this.canvas.requestRenderAll();
    }
    // Handle mouse up event
    onMouseUp() {
      if (!this.isActive || !this.isDrawing || !this.tempMask) return;
      this.isDrawing = false;
      const redMask = new fabric.Rect({
        left: this.tempMask.left,
        top: this.tempMask.top,
        width: this.tempMask.width,
        height: this.tempMask.height,
        fill: "rgba(255, 0, 0, 1)",
        // Semi-transparent red
        stroke: "red",
        strokeWidth: 2,
        selectable: true,
        // Allow moving and resizing
        hasControls: true
        // Enable resizing
      });
      this.canvas.remove(this.tempMask);
      this.canvas.add(redMask);
      this.canvas.setActiveObject(redMask);
      this.startPoint = null;
      this.tempMask = null;
      this.canvas.requestRenderAll();
    }
  };

  // src/controls/uploadImageInCanvas.js
  var UploadImageInCanvas = class {
    constructor(canvas, enableImageButton) {
      this.canvas = canvas;
      this.enableImageButton = enableImageButton;
    }
    // Activate the control (always triggers file input)
    activate() {
      console.log("\u{1F532} Image Upload Activated!");
      this.enableImageButton.classList.add("active");
      const inputElement = document.createElement("input");
      inputElement.type = "file";
      inputElement.accept = "image/*";
      inputElement.style.display = "none";
      document.body.appendChild(inputElement);
      inputElement.click();
      inputElement.addEventListener("change", (event) => {
        this.handleFileUpload(event, inputElement);
      }, { once: true });
      inputElement.addEventListener("click", () => setTimeout(() => inputElement.remove(), 500), { once: true });
    }
    // Deactivate the control (reset state after uploading)
    deactivate() {
      this.enableImageButton.classList.remove("active");
      console.log("\u{1F532} Image Upload Deactivated!");
    }
    // Handle file upload
    handleFileUpload(event, inputElement) {
      const file = event.target.files[0];
      if (!file) {
        this.deactivate();
        inputElement.remove();
        return;
      }
      const reader = new FileReader();
      reader.onload = (e) => {
        fabric.Image.fromURL(e.target.result, (img) => {
          img.set({
            left: 50,
            // Default position
            top: 50,
            scaleX: 0.5,
            // Scale image to fit
            scaleY: 0.5,
            selectable: true,
            // Allow resizing and moving
            hasControls: true
            // Show resize handles
          });
          this.canvas.add(img);
          this.canvas.setActiveObject(img);
          this.canvas.requestRenderAll();
          console.log("\u{1F5BC}\uFE0F Image Added!");
          inputElement.remove();
          this.deactivate();
        });
      };
      reader.readAsDataURL(file);
    }
  };

